props.initialCode:
// Simulating the two-level architecture
const sentence = 'John gave Mary the book';
const tokens = sentence.split(' ');

// Level 1: Token processing
const tokenEmbeddings = tokens.map((t, i) => ({
  token: t,
  // Simplified: position encoding
  embedding: [Math.cos(i * 0.5), Math.sin(i * 0.5), Math.random() * 0.3]
}));

// Level 2: Thought state aggregation
const thoughtState = {
  event: 'ATRANS',
  agent: 'John',
  patient: 'book',
  source: 'John',
  destination: 'Mary',
  stateChanges: {
    John: { possession: -1 },
    Mary: { possession: +1 },
    book: { custodian: 'John → Mary' }
  }
};

return (
  <div style={{fontFamily: 'monospace', padding: 16}}>
    <div style={{marginBottom: 16}}>
      <strong>Level 1 — Token Embeddings:</strong>
      <div style={{display: 'flex', gap: 8, marginTop: 8, flexWrap: 'wrap'}}>
        {tokenEmbeddings.map((t, i) => (
          <div key={i} style={{
            background: `hsl(${i * 60}, 70%, 85%)`,
            padding: '8px 12px', borderRadius: 8, fontSize: 13
          }}>
            <div style={{fontWeight: 'bold'}}>{t.token}</div>
            <div style={{fontSize: 10, opacity: 0.7}}>
              [{t.embedding.map(v => v.toFixed(2)).join(', ')}]
            </div>
          </div>
        ))}
      </div>
    </div>
    <div style={{fontSize: 24, textAlign: 'center'}}>⬇️ aggregate ⬇️</div>
    <div style={{background: '#1a1a2e', color: '#e0e0ff', padding: 16, borderRadius: 12, marginTop: 8}}>
      <strong>Level 2 — Thought State:</strong>
      <div style={{marginTop: 8}}>
        <div>Operator: <span style={{color: '#ffd700', fontWeight: 'bold'}}>{thoughtState.event}</span></div>
        <div>Agent: {thoughtState.agent} | Patient: {thoughtState.patient}</div>
        <div>Source: {thoughtState.source} → Dest: {thoughtState.destination}</div>
        <div style={{marginTop: 8, borderTop: '1px solid #333', paddingTop: 8}}>
          <strong>State Changes:</strong>
          {Object.entries(thoughtState.stateChanges).map(([entity, changes]) => (
            <div key={entity} style={{marginLeft: 16}}>
              {entity}: {JSON.stringify(changes)}
            </div>
          ))}
        </div>
      </div>
    </div>
  </div>
);

const levels = [
  {
    name: 'MACRO — Thought States',
    color: '#ffd700',
    bg: '#2d2200',
    items: ['ATRANS(thief, purse, woman→thief)', 'EXPEL(woman, scream)'],
    desc: 'Event-level operators transform entity states'
  },
  {
    name: 'MESO — Token Processing',
    color: '#00bfff',
    bg: '#002233',
    items: ['The', 'thief', 'snatched', 'the', 'purse'],
    desc: 'Standard attention contextualizes tokens'
  },
  {
    name: 'MICRO — Sub-Token Concepts',
    color: '#ff69b4',
    bg: '#330022',
    items: ['snatch', '-ed', 'purse', 'thief'],
    desc: 'Morphemes & semantic features via product quantization'
  }
];

return (
  <div style={{fontFamily: 'sans-serif', padding: 12}}>
    {levels.map((level, i) => (
      <div key={i} style={{
        background: level.bg, border: `2px solid ${level.color}`,
        borderRadius: 12, padding: 14, marginBottom: 10
      }}>
        <div style={{color: level.color, fontWeight: 'bold', fontSize: 15, marginBottom: 6}}>
          {level.name}
        </div>
        <div style={{color: '#ccc', fontSize: 12, marginBottom: 8}}>{level.desc}</div>
        <div style={{display: 'flex', gap: 6, flexWrap: 'wrap'}}>
          {level.items.map((item, j) => (
            <span key={j} style={{
              background: level.color + '22', color: level.color,
              padding: '4px 10px', borderRadius: 6, fontSize: 12,
              border: `1px solid ${level.color}44`
            }}>{item}</span>
          ))}
        </div>
      </div>
    ))}
    <div style={{textAlign: 'center', color: '#888', fontSize: 12, marginTop: 4}}>
      ↕ Information flows bidirectionally between all three levels
    </div>
  </div>
);

const [step, setStep] = React.useState(0);
const narrative = [
  { text: 'The chef chopped the onion.', op: 'SEPARATE', agent: 'chef', patient: 'onion', stateChange: 'onion: whole → pieces' },
  { text: 'She tossed them into the pan.', op: 'PTRANS', agent: 'chef', patient: 'onion pieces', stateChange: 'onion: counter → pan' },
  { text: 'The oil sizzled loudly.', op: 'EXPEL', agent: 'oil', patient: 'sound', stateChange: 'oil: hot + disturbed' },
  { text: 'She seasoned the dish.', op: 'ATRANS', agent: 'chef', patient: 'seasoning', stateChange: 'dish: unseasoned → seasoned' }
];

const worldState = {};
narrative.slice(0, step + 1).forEach(n => { worldState[n.patient] = n.stateChange; });

return (
  <div style={{fontFamily: 'sans-serif', padding: 12}}>
    <div style={{display: 'flex', gap: 6, marginBottom: 16, flexWrap: 'wrap'}}>
      {narrative.map((n, i) => (
        <button key={i} onClick={() => setStep(i)} style={{
          padding: '6px 12px', borderRadius: 8, fontSize: 12, cursor: 'pointer',
          background: i === step ? '#ffd700' : i < step ? '#333' : '#1a1a1a',
          color: i === step ? '#000' : '#888',
          border: i === step ? '2px solid #ffd700' : '1px solid #444'
        }}>Step {i + 1}</button>
      ))}
    </div>
    <div style={{background: '#1a1a2e', padding: 16, borderRadius: 12, marginBottom: 12}}>
      <div style={{color: '#aaa', fontSize: 11, marginBottom: 4}}>CURRENT SENTENCE:</div>
      <div style={{color: '#fff', fontSize: 16, marginBottom: 12}}>"{narrative[step].text}"</div>
      <div style={{display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12}}>
        <div>
          <div style={{color: '#ffd700', fontSize: 12, fontWeight: 'bold'}}>OPERATOR</div>
          <div style={{color: '#ffd700', fontSize: 20}}>{narrative[step].op}</div>
        </div>
        <div>
          <div style={{color: '#00bfff', fontSize: 12, fontWeight: 'bold'}}>ROLES</div>
          <div style={{color: '#00bfff', fontSize: 13}}>Agent: {narrative[step].agent}</div>
          <div style={{color: '#00bfff', fontSize: 13}}>Patient: {narrative[step].patient}</div>
        </div>
      </div>
    </div>
    <div style={{background: '#0a1a0a', border: '1px solid #2a4a2a', padding: 14, borderRadius: 12}}>
      <div style={{color: '#4CAF50', fontSize: 12, fontWeight: 'bold', marginBottom: 8}}>🌍 WORLD STATE (Working Memory)</div>
      {Object.entries(worldState).map(([entity, state]) => (
        <div key={entity} style={{color: '#8BC34A', fontSize: 13, marginBottom: 4}}>
          <strong>{entity}:</strong> {state}
        </div>
      ))}
    </div>
  </div>
);
